var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"큽……!","JPN":"くっ……！","ENG":"Ngh...!","TWN":"咳……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"CRF가 거의 소진된 상태일 텐데 이렇게 버틸 수 있다니…….","JPN":"CRFがほとんど底をついた状態だろうに、ここまで耐えられるとは……","ENG":"Your CRF should be nearly depleted by now, and yet you're still holding on...","TWN":"CRF幾乎耗盡了，竟然還能堅持……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"반쪽짜리인 나와 자네의 차이가 이정도라는 사실이 믿기지 않는군.","JPN":"半端者の私と君との差がこれほどまでとは信じがたい。","ENG":"I can hardly believe the difference between us.","TWN":"真是難以置信，我和你之間的差距竟然如此之大。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"반쪽짜리는 무슨…… 이도저도 아닌 괴물 주제에……!","JPN":"何が半端者だ……どっちつかずの化け物のくせに……！","ENG":"Difference? You're just a freak of nature...!","TWN":"什麼半吊子……明明是個不倫不類的怪物……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"상처의 재생이 더뎌지고 있어.","JPN":"傷の再生が遅くなってる。","ENG":"My wounds aren't healing as fast.","TWN":"傷口癒合得越來越慢了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어째서지? CRF와 재생력은 관계가 없을 텐데?","JPN":"どうして？　CRFと再生力は関係ないはず。","ENG":"But why? CRF and regeneration shouldn't be related...","TWN":"為什麼會這樣？CRF和再生能力應該沒有關係啊？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"왜 상처가 회복되지 않는지 궁금한 눈치군.","JPN":"なぜ傷が回復しないのか、気になるようだな。","ENG":"I see you're wondering why your wounds won't heal.","TWN":"你似乎在好奇為什麼傷口無法恢復。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"은을 정제해 이터니움과 섞은 특제 탄환 때문이네.","JPN":"銀を精製してエタニウムと混合した、特製弾丸のためさ。","ENG":"It's thanks to my custom bullets, refined with silver and mixed with Eternium.","TWN":"因為這是用精煉的銀和永恆之金混合製成的特製彈藥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"역시, 자네의 상처는 쉽게 재생되지 않고 있군.","JPN":"やはり、なかなか傷が治らない様子だな。","ENG":"As expected, your wounds aren't regenerating properly.","TWN":"效果就是讓你的傷口沒有那麼容易癒合。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아직까진 합의체의 연구 기록과 일치해.","JPN":"今のところ、合意体の研究記録と一致している。","ENG":"So far, everything matches the Northern Union's research records.","TWN":"目前為止和和議會的研究記錄一致。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽…… 헤헤헤…….","JPN":"うっ……へへへ……","ENG":"Ugh... Hehehe...","TWN":"呃……嘿嘿嘿……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이 상황에서도 여유를 부리는군.","JPN":"この状況でまだ余裕ぶるのか。","ENG":"Still acting calm in a situation like this?","TWN":"在這種情況下還這麼悠閒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이유가 뭐지?","JPN":"なぜだ？","ENG":"Why is that?","TWN":"這是為什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아직 숨기고 있는 다른 무기가 있는 건가?","JPN":"まさか、隠し持った武器でも他にあるのか？","ENG":"Do you still have some secret weapon up your sleeve?","TWN":"還有其他隱藏的武器嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무기는…… 무슨 무기야…… 빌어먹을 자식아…….","JPN":"武器ね……そんなわけないでしょう……このくそ野郎……","ENG":"Weapon...? I wish...","TWN":"武器……什麼武器……你這個混蛋……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"상처 회복도 안 되고…… 힘을 해방할 수도 없다고…….","JPN":"傷も回復しないし……力を解放することもできない……","ENG":"I can't heal... I can't unleash my power...","TWN":"傷口無法癒合……力量也無法解放……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"근데…… 웃기잖아.","JPN":"でも……笑えるじゃない。","ENG":"And yet... this is all just hilarious.","TWN":"不過……很搞笑吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"너 하나 살자고 이런 짓을 벌이는 게.","JPN":"あなた1人が生きるために、こんなことをしてるなんて。","ENG":"You did all this just so you could live.","TWN":"為了讓你自己一個人活命，竟然做出這種事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네 가족들, 부하들 다 먹어 치웠으면서, 혼자 살아서 뭐 하냐?","JPN":"家族も部下も全部食らいつくして、1人で生き残って何になる？","ENG":"You devoured your own family, your own servants... and for what? To stay alive?","TWN":"你吃掉了你的家人和僕人，自己一個人活著有什麼意義？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"난…… 그게 싫어서…… 젠장…….","JPN":"私は……それがいやだったから……くそ……","ENG":"I... I'd never do that... Damn it...","TWN":"我……就討厭這種人……該死……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"너도 그 지옥 같은 곳에 있었다면…….","JPN":"あなたもあの地獄のような場所にいたんだろ……？","ENG":"If you've been through that same hell as I have...","TWN":"如果你也在那個地獄般的地方……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알아야 할 거 아니야……!","JPN":"なのに、どうしてそれがわからない……！","ENG":"Then you would know...!","TWN":"你應該會知道的……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"10년 전, 쾰른","JPN":"10年前、ケルン……","ENG":"10 years ago, Cologne","TWN":"10年前，科隆"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"원인 불명의 기상 재해가 발생하였습니다.","JPN":"原因不明の気象災害が発生しました。","ENG":"An unidentified weather anomaly has occurred.","TWN":"發生了不明原因的氣象災害。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_POLICE"},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"시민분들은 모두 창문을 <color=#ff3636>열고</color> 달을 <color=#ff3636>바라보십시오.</color>","JPN":"市民の皆さまは窓を<color=#ff3636>開けて</color>月を<color=#ff3636>見てください</color>。","ENG":"All citizens, please <color=#ff3636>open</color> your windows and <color=#ff3636>look</color> at the moon.","TWN":"市民們請全部打開<color=#ff3636>窗戶</color>，仰望<color=#ff3636>月亮</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};